<section class="section"><div class="section-title"><span>PARTNER PORTAL</span><h1>Affiliate Dashboard</h1></div><?php if(!$affiliate):?><div class="empty"><p>You have not registered for the affiliate program.</p><a class="btn" href="<?=url('affiliate')?>">Register Now</a></div><?php else:?><div class="stats"><article><b><?=e(ucfirst($affiliate['status']))?></b><span>Account status</span></article><article><b><?=e($affiliate['commission_rate'])?>%</b><span>Commission rate</span></article><article><b>৳<?=number_format((float)$affiliate['paid_total'],2)?></b><span>Paid</span></article><article><b>৳<?=number_format((float)$affiliate['pending_total'],2)?></b><span>Pending</span></article></div><div class="admin-panel"><h2>Your referral link</h2><?php $link=url('r?ref='.$affiliate['affiliate_code']);?><input class="copy-link" readonly value="<?=e($link)?>"><p>Code: <b><?=e($affiliate['affiliate_code'])?></b>. Tracking begins only after administrator approval.</p></div><div class="admin-panel"><h2>Commission history</h2><div class="table-wrap"><table><thead><tr><th>Date</th><th>Description</th><th>Amount</th><th>Status</th></tr></thead><tbody><?php foreach($affiliate['commissions'] as$c):?><tr><td><?=date('d M Y',strtotime($c['created_at']))?></td><td><?=e($c['description'])?></td><td>৳<?=number_format((float)$c['amount'],2)?></td><td><?=e(ucfirst($c['status']))?></td></tr><?php endforeach;?></tbody></table></div></div><?php endif;?></section>
